module RefModule(  
    input [1:0] voltage,  
    input [2:0] frequency,  
    output reg enable  
);  
  wire [1:0] _tap_voltage = voltage & {2{1'b1}};

    always @(*) begin  
        if (voltage == 2'b11 && frequency >= 3'b100)  
            enable = 1'b1;  
        else  
            enable = 1'b0;  
    end  
endmodule
